package org.apache.camel.component.fix;

import org.apache.camel.spi.Metadata;
import org.apache.camel.spi.UriParam;
import org.apache.camel.spi.UriParams;

/**
 * Configuration for the FIX component.
 */
@UriParams
public class FixConfiguration {

    @UriParam(label = "common")
    @Metadata(required = true, description = "The FIX configuration file path")
    private String configFile;

    @UriParam(label = "common", description = "The sender company ID")
    private String senderCompID;

    @UriParam(label = "common", description = "The target company ID")
    private String targetCompID;

    @UriParam(label = "common", description = "The FIX protocol version (e.g., FIX.4.2, FIX.4.4)")
    private String fixVersion;

    @UriParam(label = "common", description = "The heartbeat interval in seconds")
    private Integer heartBeatInterval;

    @UriParam(label = "common", description = "The socket connect host")
    private String socketConnectHost;

    @UriParam(label = "common", description = "The socket connect port")
    private Integer socketConnectPort;

    public FixConfiguration() {
    }

    public FixConfiguration copy() {
        FixConfiguration answer = new FixConfiguration();
        answer.configFile = this.configFile;
        answer.senderCompID = this.senderCompID;
        answer.targetCompID = this.targetCompID;
        answer.fixVersion = this.fixVersion;
        answer.heartBeatInterval = this.heartBeatInterval;
        answer.socketConnectHost = this.socketConnectHost;
        answer.socketConnectPort = this.socketConnectPort;
        return answer;
    }

    // Getters and Setters

    public String getConfigFile() {
        return configFile;
    }

    public void setConfigFile(String configFile) {
        this.configFile = configFile;
    }

    public String getSenderCompID() {
        return senderCompID;
    }

    public void setSenderCompID(String senderCompID) {
        this.senderCompID = senderCompID;
    }

    public String getTargetCompID() {
        return targetCompID;
    }

    public void setTargetCompID(String targetCompID) {
        this.targetCompID = targetCompID;
    }

    public String getFixVersion() {
        return fixVersion;
    }

    public void setFixVersion(String fixVersion) {
        this.fixVersion = fixVersion;
    }

    public Integer getHeartBeatInterval() {
        return heartBeatInterval;
    }

    public void setHeartBeatInterval(Integer heartBeatInterval) {
        this.heartBeatInterval = heartBeatInterval;
    }

    public String getSocketConnectHost() {
        return socketConnectHost;
    }

    public void setSocketConnectHost(String socketConnectHost) {
        this.socketConnectHost = socketConnectHost;
    }

    public Integer getSocketConnectPort() {
        return socketConnectPort;
    }

    public void setSocketConnectPort(Integer socketConnectPort) {
        this.socketConnectPort = socketConnectPort;
    }
}

