package org.apache.camel.component.fix;

import org.apache.camel.Processor;
import org.apache.camel.support.DefaultConsumer;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

/**
 * FIX Protocol consumer that receives inbound FIX messages and feeds them into Camel routes.
 */
public class FixConsumer extends DefaultConsumer {

    private static final Logger LOG = LoggerFactory.getLogger(FixConsumer.class);

    private final FixConfiguration configuration;

    public FixConsumer(FixEndpoint endpoint, Processor processor, FixConfiguration configuration) {
        super(endpoint, processor);
        this.configuration = configuration;
    }

    @Override
    protected void doStart() throws Exception {
        super.doStart();
        LOG.debug("FIX Consumer starting for session: {}", getEndpoint().getSessionID());
        // Initialize FIX acceptor session and message handling
        // This would typically initialize a FIX engine acceptor
        // and register callbacks for incoming messages
    }

    @Override
    protected void doStop() throws Exception {
        super.doStop();
        LOG.debug("FIX Consumer stopping for session: {}", getEndpoint().getSessionID());
        // Stop the FIX acceptor session and clean up resources
    }

    @Override
    public FixEndpoint getEndpoint() {
        return (FixEndpoint) super.getEndpoint();
    }

    public FixConfiguration getConfiguration() {
        return configuration;
    }
}

