package org.apache.camel.component.fix;

import org.apache.camel.AsyncCallback;
import org.apache.camel.Exchange;
import org.apache.camel.support.DefaultAsyncProducer;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

/**
 * FIX Protocol producer that sends outbound FIX messages from Camel exchanges.
 */
public class FixProducer extends DefaultAsyncProducer {

    private static final Logger LOG = LoggerFactory.getLogger(FixProducer.class);

    private final FixConfiguration configuration;

    public FixProducer(FixEndpoint endpoint, FixConfiguration configuration) {
        super(endpoint);
        this.configuration = configuration;
    }

    @Override
    public FixEndpoint getEndpoint() {
        return (FixEndpoint) super.getEndpoint();
    }

    @Override
    public boolean process(Exchange exchange, AsyncCallback callback) {
        try {
            LOG.debug("Processing FIX message for session: {}", getEndpoint().getSessionID());

            // Extract the FIX message from the exchange body
            Object body = exchange.getMessage().getBody();

            // Send the FIX message through the FIX session
            // This would typically use a FIX engine to send the message
            sendFixMessage(body, exchange);

            // Callback to indicate successful processing
            callback.done(false);
            return true;
        } catch (Exception e) {
            LOG.error("Error processing FIX message", e);
            exchange.setException(e);
            callback.done(false);
            return true;
        }
    }

    private void sendFixMessage(Object body, Exchange exchange) throws Exception {
        // Send the FIX message to the FIX session
        // Implementation would depend on the actual FIX engine being used
        LOG.debug("Sending FIX message: {}", body);
    }

    public FixConfiguration getConfiguration() {
        return configuration;
    }
}

