package org.apache.camel.component.fix;

import org.apache.camel.test.spring.junit5.CamelSpringTestSupport;
import org.junit.jupiter.api.Test;
import org.springframework.context.support.ClassPathXmlApplicationContext;

import static org.junit.jupiter.api.Assertions.assertNotNull;

/**
 * Test for FIX component.
 */
public class FixComponentTest extends CamelSpringTestSupport {

    @Override
    protected ClassPathXmlApplicationContext createApplicationContext() {
        return new ClassPathXmlApplicationContext("classpath:/test-fix-context.xml");
    }

    @Test
    public void testFixComponentExists() {
        FixComponent component = context.getComponent("fix", FixComponent.class);
        assertNotNull(component);
    }

    @Test
    public void testCreateEndpoint() throws Exception {
        FixEndpoint endpoint = context.getEndpoint("fix:test-session", FixEndpoint.class);
        assertNotNull(endpoint);
        assertNotNull(endpoint.getSessionID());
    }
}

