17: package org.apache.camel.component.netty;
18: 
19: import java.net.URI;
20: import java.util.HashMap;
21: import java.util.Map;
22: 
23: import io.netty.util.NettyRuntime;
24: import io.netty.util.concurrent.EventExecutorGroup;
25: import io.netty.util.internal.SystemPropertyUtil;
26: import org.apache.camel.CamelContext;
27: import org.apache.camel.Endpoint;
28: import org.apache.camel.SSLContextParametersAware;
29: import org.apache.camel.spi.BeanIntrospection;
30: import org.apache.camel.spi.Metadata;
31: import org.apache.camel.spi.annotations.Component;
32: import org.apache.camel.support.DefaultComponent;
33: import org.apache.camel.support.PluginHelper;
