37: 
38: @Component("netty")
39: public class NettyComponent extends DefaultComponent implements SSLContextParametersAware {
40: 
41:     private static final Logger LOG = LoggerFactory.getLogger(NettyComponent.class);
42: 
43:     @Metadata(description = "To use the NettyConfiguration as configuration when creating endpoints")
44:     private NettyConfiguration configuration = new NettyConfiguration();
45:     @Metadata(label = "consumer,advanced",
46:               description = "Sets a maximum thread pool size for the netty consumer ordered thread pool. The default size is 2 x cpu_core plus"
47:                             + " 1. Setting this value to eg 10 will then use 10 threads unless 2 x cpu_core plus 1 is a higher value, which then"
48:                             + " will override and be used. For example if there are 8 cores, then the consumer thread pool will be 17."
49:                             + " This thread pool is used to route messages received from Netty by Camel. We use a separate thread pool to ensure"
50:                             + " ordering of messages and also in case some messages will block, then nettys worker threads (event loop) wont be affected.")
51:     private int maximumPoolSize;
52:     @Metadata(label = "consumer,advanced", description = "To use the given custom EventExecutorGroup.")
53:     private volatile EventExecutorGroup executorService;
54:     @Metadata(label = "security", description = "Enable usage of global SSL context parameters.")
55:     private boolean useGlobalSslContextParameters;
56: 
57:     public NettyComponent() {
58:     }
59: 
60:     public NettyComponent(Class<? extends Endpoint> endpointClass) {
61:     }
62: 
63:     public NettyComponent(CamelContext context) {
64:         super(context);
65:     }
66: 
67:     public int getMaximumPoolSize() {
68:         return maximumPoolSize;
69:     }
70: 
71:     /**
72:      * Sets a maximum thread pool size for the netty consumer ordered thread pool. The default size is 2 x cpu_core plus
73:      * 1. Setting this value to eg 10 will then use 10 threads unless 2 x cpu_core plus 1 is a higher value, which then
74:      * will override and be used. For example if there are 8 cores, then the consumer thread pool will be 17.
75:      *
76:      * This thread pool is used to route messages received from Netty by Camel. We use a separate thread pool to ensure
77:      * ordering of messages and also in case some messages will block, then nettys worker threads (event loop) wont be
78:      * affected.
79:      */
80:     public void setMaximumPoolSize(int maximumPoolSize) {
81:         this.maximumPoolSize = maximumPoolSize;
82:     }
83: 
84:     @Override
85:     protected Endpoint createEndpoint(String uri, String remaining, Map<String, Object> parameters) throws Exception {
86:         NettyConfiguration config = configuration.copy();
87:         config = parseConfiguration(config, remaining, parameters);
88: 
89:         // merge any custom bootstrap configuration on the config
90:         NettyServerBootstrapConfiguration bootstrapConfiguration = resolveAndRemoveReferenceParameter(parameters,
91:                 "bootstrapConfiguration", NettyServerBootstrapConfiguration.class);
92:         if (bootstrapConfiguration != null) {
93:             Map<String, Object> options = new HashMap<>();
94:             BeanIntrospection beanIntrospection = PluginHelper.getBeanIntrospection(getCamelContext());
95:             if (beanIntrospection.getProperties(bootstrapConfiguration, options, null, false)) {
96:                 PropertyBindingSupport.bindProperties(getCamelContext(), config, options);
97:             }
98:         }
99: 
100:         if (config.getSslContextParameters() == null) {
101:             config.setSslContextParameters(retrieveGlobalSslContextParameters());
102:         }
103: 
104:         // validate config
105:         config.validateConfiguration();
106: 
107:         NettyEndpoint nettyEndpoint = new NettyEndpoint(uri, this, config);
108:         setProperties(nettyEndpoint, parameters);
109:         return nettyEndpoint;
110:     }
111: 
112:     /**
113:      * Parses the configuration
114:      *
115:      * @return the parsed and valid configuration to use
116:      */
117:     protected NettyConfiguration parseConfiguration(
118:             NettyConfiguration configuration, String remaining, Map<String, Object> parameters)
119:             throws Exception {
120:         configuration.parseURI(new URI(remaining), parameters, this, "tcp", "udp");
121:         return configuration;
122:     }
123: 
124:     public NettyConfiguration getConfiguration() {
125:         return configuration;
126:     }
127: 
128:     /**
129:      * To use the NettyConfiguration as configuration when creating endpoints.
130:      */
131:     public void setConfiguration(NettyConfiguration configuration) {
132:         this.configuration = configuration;
133:     }
134: 
135:     /**
136:      * To use the given EventExecutorGroup.
137:      */
138:     public void setExecutorService(EventExecutorGroup executorService) {
139:         this.executorService = executorService;
140:     }
141: 
142:     @Override
143:     public boolean isUseGlobalSslContextParameters() {
144:         return this.useGlobalSslContextParameters;
145:     }
146: 
147:     /**
148:      * Enable usage of global SSL context parameters.
149:      */
150:     @Override
151:     public void setUseGlobalSslContextParameters(boolean useGlobalSslContextParameters) {
152:         this.useGlobalSslContextParameters = useGlobalSslContextParameters;
153:     }
154: 
155:     public EventExecutorGroup getExecutorService() {
156:         return executorService;
157:     }
158: 
159:     @Override
160:     protected void doStart() throws Exception {
161:         //Only setup the executorService if it is needed
162:         if (configuration.isUsingExecutorService() && executorService == null) {
163:             int netty = SystemPropertyUtil.getInt("io.netty.eventLoopThreads", NettyRuntime.availableProcessors() * 2);
164:             // we want one more thread than netty uses for its event loop
165:             // and if there is a custom size for maximum pool size then use it, unless netty event loops has more threads
166:             // and therefore we use math.max to find the highest value
167:             int threads = Math.max(maximumPoolSize, netty + 1);
168:             executorService = NettyHelper.createExecutorGroup(getCamelContext(), "NettyConsumerExecutorGroup", threads);
169:             LOG.info("Creating shared NettyConsumerExecutorGroup with {} threads", threads);
170:         }
171: 
172:         super.doStart();
173:     }
174: 
175:     @Override
176:     protected void doStop() throws Exception {
177:         //Only shutdown the executorService if it is created by netty component
178:         if (configuration.isUsingExecutorService() && executorService != null) {
179:             getCamelContext().getExecutorServiceManager().shutdownGraceful(executorService);
180:             executorService = null;
181:         }
182: 
183:         //shutdown workerPool if configured
184:         if (configuration.getWorkerGroup() != null) {
185:             configuration.getWorkerGroup().shutdownGracefully();
186:         }
187: 
188:         super.doStop();
189:     }
190: 
191: }
