45: @UriEndpoint(firstVersion = "2.14.0", scheme = "netty", title = "Netty", syntax = "netty:protocol://host:port",
46:              category = { Category.NETWORKING }, headersClass = NettyConstants.class)
47: public class NettyEndpoint extends DefaultEndpoint implements AsyncEndpoint, EndpointServiceLocation {
48:     @UriParam
49:     private NettyConfiguration configuration;
50:     @UriParam(defaultValue = "false", label = "advanced",
51:               description = "Sets whether synchronous processing should be strictly used")
52:     private boolean synchronous;
53: 
54:     public NettyEndpoint(String endpointUri, NettyComponent component, NettyConfiguration configuration) {
55:         super(endpointUri, component);
56:         this.configuration = configuration;
57:     }
58: 
