60:     public String getServiceUrl() {
61:         return configuration.getProtocol() + ":" + configuration.getHost() + ":" + configuration.getPort();
62:     }
63: 
64:     @Override
65:     public String getServiceProtocol() {
66:         return configuration.getProtocol();
67:     }
68: 
69:     public boolean isSynchronous() {
70:         return synchronous;
71:     }
72: 
73:     /**
74:      * Sets whether synchronous processing should be strictly used
75:      */
76:     public void setSynchronous(boolean synchronous) {
77:         this.synchronous = synchronous;
78:     }
79: 
80:     @Override
81:     public Consumer createConsumer(Processor processor) throws Exception {
82:         Consumer answer = new NettyConsumer(this, processor, configuration);
83:         configureConsumer(answer);
84:         return answer;
85:     }
86: 
87:     @Override
88:     public Producer createProducer() throws Exception {
89:         Producer answer = new NettyProducer(this, configuration);
90:         if (isSynchronous()) {
91:             return new SynchronousDelegateProducer(answer);
92:         } else {
93:             return answer;
94:         }
95:     }
96: 
97:     @Override
98:     public NettyComponent getComponent() {
99:         return (NettyComponent) super.getComponent();
100:     }
